css:
@import url('https://fonts.loli.net/css2?family=LXGW+WenKai+Mono+TC:wght@400;700&display=swap');
@import url('https://fonts.googleapis.com/css2?family=Noto+Serif+SC:wght@400;500;700&display=swap');

/* =====================================================
 * 抽屉内容脱离限制 - 最高优先级规则
 * ===================================================== */

/* 核心修复:移除所有可能限制子元素的父级属性 */
#top-settings-holder,
#top-settings-holder .drawer,
#top-settings-holder > .drawer {
  overflow: visible !important;
  contain: none !important;
  perspective: none !important;
  transform-style: flat !important;
  mask: none !important;
  -webkit-mask: none !important;
}

/* --- 强制抽屉内容独立于父级容器 --- */
/* 
 * 关键修复:确保所有 drawer-content 完全脱离父级容器限制
 * 使用多层选择器覆盖所有可能的情况
 * 排除侧边导航面板和独立浮动窗口,它们有自己的定位规则
 */
#top-settings-holder .drawer .drawer-content:not(#right-nav-panel):not(#left-nav-panel):not(#floatingPrompt):not(#cfgConfig):not(#logprobsViewer),
#top-settings-holder > .drawer > .drawer-content:not(#right-nav-panel):not(#left-nav-panel):not(#floatingPrompt):not(#cfgConfig):not(#logprobsViewer),
#top-settings-holder .drawer-content:not(#right-nav-panel):not(#left-nav-panel):not(#floatingPrompt):not(#cfgConfig):not(#logprobsViewer),
body > .drawer-content:not(#right-nav-panel):not(#left-nav-panel):not(#floatingPrompt):not(#cfgConfig):not(#logprobsViewer) {
  /* 强制固定定位 - 相对于视口,不是父级 */
  position: fixed !important;
  /* 移除所有可能创建新层叠上下文的属性 */
  transform: none !important;
  transform-style: flat !important;
  perspective: none !important;
  filter: none !important;
  will-change: auto !important;
  isolation: auto !important;
  contain: none !important;
  /* 确保不被裁剪 */
  clip: auto !important;
  clip-path: none !important;
  overflow: visible auto !important;
  /* 移除尺寸限制 */
  max-width: none !important;
  max-height: none !important;
  min-width: 0 !important;
  min-height: 0 !important;
  /* 确保独立于父级的边距和定位 */
  margin: 0 !important;
}

/* --- 左侧导航栏 --- */
#top-settings-holder {
  position: fixed !important;
  top: 0 !important;
  left: 0 !important;
  transform: none !important;
  width: var(--nav-bar-width) !important;
  height: 100vh !important;
  margin: 0 !important;
  padding: 12px 0 !important;
  z-index: 1000 !important;
  display: flex !important;
  flex-direction: column !important;
  align-items: center !important;
  justify-content: flex-start !important;
  gap: 6px !important;
  background: linear-gradient(
    180deg,
    rgba(20, 24, 30, 0.98) 0%,
    rgba(26, 31, 39, 0.95) 100%
  ) !important;
  backdrop-filter: blur(18px) saturate(1.25) !important;
  -webkit-backdrop-filter: blur(18px) saturate(1.25) !important;
  border: none !important;
  border-right: 1px solid rgba(130, 233, 222, 0.25) !important;
  border-radius: 0 !important;
  box-shadow:
    6px 0 28px rgba(0, 0, 0, 0.35),
    inset -1px 0 0 rgba(130, 233, 222, 0.12) !important;
  transition: background 0.4s cubic-bezier(0.4, 0, 0.2, 1) !important;
  overflow: visible !important;
  flex-shrink: 0 !important;
  /* 防止创建新的层叠上下文限制子元素 */
  contain: none !important;
  perspective: none !important;
  transform-style: flat !important;
}

/* 容器悬停效果 */
#top-settings-holder:hover {
  background: linear-gradient(
    180deg,
    rgba(24, 29, 36, 0.98) 0%,
    rgba(30, 35, 43, 0.95) 100%
  ) !important;
  border-right-color: rgba(130, 233, 222, 0.35) !important;
  box-shadow:
    8px 0 32px rgba(0, 0, 0, 0.4),
    inset -1px 0 0 rgba(130, 233, 222, 0.18) !important;
}

#top-settings-holder::before {
  content: "";
  width: 56px;
  height: 56px;
  border-radius: 18px;
  border: 1px solid rgba(130, 233, 222, 0.3);
  background: linear-gradient(
    135deg,
    rgba(130, 233, 222, 0.12) 0%,
    rgba(249, 164, 200, 0.08) 100%
  );
  display: flex;
  align-items: center;
  justify-content: center;
  transition: transform 0.35s var(--transition-easing),
              box-shadow 0.35s var(--transition-easing),
              border-color 0.35s var(--transition-easing);
  box-shadow:
    0 6px 18px rgba(0, 0, 0, 0.35),
    inset 0 1px 0 rgba(255, 255, 255, 0.2);
  pointer-events: none;
}

#top-settings-holder:hover::before {
  background: linear-gradient(
    135deg,
    rgba(130, 233, 222, 0.25) 0%,
    rgba(249, 164, 200, 0.15) 100%
  );
  border-color: rgba(130, 233, 222, 0.7);
  transform: scale(1.1) rotate(8deg);
  box-shadow: 
    0 0 25px rgba(130, 233, 222, 0.5),
    0 0 40px rgba(249, 164, 200, 0.3),
    inset 0 1px 0 rgba(255, 255, 255, 0.2);
  animation: logoBreath 2s ease-in-out infinite;
}

/* Logo呼吸动画 */
@keyframes logoBreath {
  0%, 100% {
    box-shadow: 
      0 0 20px rgba(130, 233, 222, 0.4),
      0 0 35px rgba(249, 164, 200, 0.2);
  }
  50% {
    box-shadow: 
      0 0 30px rgba(130, 233, 222, 0.6),
      0 0 50px rgba(249, 164, 200, 0.4);
  }
}

/* 分割线 */
#top-settings-holder::after {
  content: "";
  width: 40px;
  height: 2px;
  background: linear-gradient(
    90deg,
    transparent,
    rgba(130, 233, 222, 0.4),
    transparent
  );
  margin: 8px 0;
  flex-shrink: 0;
}

/* --- 导航按钮样式 --- */
#top-settings-holder .drawer {
  width: 52px !important;
  height: 52px !important;
  min-width: 52px !important;
  min-height: 52px !important;
  margin: 4px 0 !important;
  border: none !important;
  background: transparent !important;
  border-radius: 16px !important;
  transition: all var(--transition-speed) var(--transition-easing) !important;
  position: static !important;
  overflow: visible !important;
  flex-shrink: 0 !important;
  contain: none !important;
}

#top-settings-holder .drawer-toggle, 
#top-settings-holder .drawer-header {
  width: 100% !important;
  height: 100% !important;
  display: flex !important;
  align-items: center !important;
  justify-content: center !important;
  background: linear-gradient(
    135deg,
    rgba(130, 233, 222, 0.08) 0%,
    rgba(249, 164, 200, 0.05) 100%
  ) !important;
  border: 1px solid rgba(130, 233, 222, 0.2) !important;
  border-radius: 16px !important;
  cursor: pointer !important;
  transition: all var(--transition-speed) var(--transition-easing) !important;
  position: relative !important;
  overflow: hidden !important;
}

/* 按钮悬停效果 */
#top-settings-holder .drawer-toggle:hover, 
#top-settings-holder .drawer-header:hover {
  background: linear-gradient(
    135deg,
    rgba(130, 233, 222, 0.18) 0%,
    rgba(249, 164, 200, 0.12) 100%
  ) !important;
  border-color: rgba(130, 233, 222, 0.5) !important;
  border-radius: 24px !important;
  box-shadow: 
    0 0 20px rgba(130, 233, 222, 0.3),
    inset 0 1px 0 rgba(255, 255, 255, 0.1) !important;
  transform: translateX(4px) !important;
}

/* 按钮活跃状态 */
#top-settings-holder .drawer-toggle.selected, 
#top-settings-holder .drawer-header.selected,
#top-settings-holder .drawer-toggle[aria-expanded="true"],
#top-settings-holder .drawer-header[aria-expanded="true"] {
  background: linear-gradient(
    135deg,
    rgba(130, 233, 222, 0.8) 0%,
    rgba(249, 164, 200, 0.6) 100%
  ) !important;
  border-color: rgba(130, 233, 222, 0.9) !important;
  border-radius: 20px !important;
  box-shadow: 
    0 0 25px rgba(130, 233, 222, 0.5),
    0 4px 12px rgba(0, 0, 0, 0.3),
    inset 0 1px 0 rgba(255, 255, 255, 0.2) !important;
  transform: translateX(4px) scale(1.05) !important;
}

/* 活跃指示器 */
#top-settings-holder .drawer-toggle.selected::before,
#top-settings-holder .drawer-header.selected::before,
#top-settings-holder .drawer-toggle[aria-expanded="true"]::before,
#top-settings-holder .drawer-header[aria-expanded="true"]::before {
  content: "";
  position: absolute;
  left: -8px;
  top: 50%;
  transform: translateY(-50%);
  width: 4px;
  height: 24px;
  background: linear-gradient(
    180deg,
    rgba(130, 233, 222, 0.9),
    rgba(249, 164, 200, 0.9)
  );
  border-radius: 0 2px 2px 0;
  box-shadow: 0 0 10px rgba(130, 233, 222, 0.6);
  animation: indicatorPulse 2s ease-in-out infinite;
}

/* 指示器脉冲动画 */
@keyframes indicatorPulse {
  0%, 100% {
    height: 20px;
    opacity: 0.8;
  }
  50% {
    height: 28px;
    opacity: 1;
  }
}

/* 图标样式 */
#top-settings-holder .drawer-icon {
  font-size: 20px !important;
  color: rgba(130, 233, 222, 0.8) !important;
  transition: all 0.3s ease !important;
  filter: drop-shadow(0 1px 2px rgba(0, 0, 0, 0.3)) !important;
  z-index: 1 !important;
}

#top-settings-holder .drawer-toggle:hover .drawer-icon,
#top-settings-holder .drawer-header:hover .drawer-icon {
  color: rgba(130, 233, 222, 1) !important;
  transform: scale(1.15) !important;
  filter: 
    drop-shadow(0 0 8px rgba(130, 233, 222, 0.6))
    drop-shadow(0 2px 4px rgba(0, 0, 0, 0.4)) !important;
}

#top-settings-holder .drawer-toggle.selected .drawer-icon,
#top-settings-holder .drawer-header.selected .drawer-icon,
#top-settings-holder .drawer-toggle[aria-expanded="true"] .drawer-icon,
#top-settings-holder .drawer-header[aria-expanded="true"] .drawer-icon {
  color: rgba(255, 255, 255, 0.95) !important;
  transform: scale(1.2) !important;
  filter: 
    drop-shadow(0 0 12px rgba(255, 255, 255, 0.4))
    drop-shadow(0 2px 4px rgba(0, 0, 0, 0.5)) !important;
}

/* --- 右侧角色面板 --- */
#left-nav-panel {
  position: fixed !important;
  right: 0px !important;
  left: auto !important;
  top: 0px !important;
  bottom: 0px !important;
  width: 0 !important;
  height: 100vh !important;
  max-height: 100vh !important;
  background: linear-gradient(
    135deg,
    rgba(26, 31, 39, 0.95) 0%,
    rgba(30, 35, 43, 0.95) 100%
  ) !important;
  backdrop-filter: blur(12px) !important;
  -webkit-backdrop-filter: blur(12px) !important;
  border: none !important;
  border-left: 1px solid rgba(130, 233, 222, 0.2) !important;
  border-radius: 0 !important;
  box-shadow: 
    -4px 0 24px rgba(0, 0, 0, 0.3),
    inset 1px 0 0 rgba(130, 233, 222, 0.08) !important;
  transition: 
    width var(--transition-speed) var(--transition-easing),
    padding var(--transition-speed) var(--transition-easing),
    opacity var(--transition-speed) ease !important;
  z-index: 999 !important;
  overflow-y: auto !important;
  overflow-x: hidden !important;
  padding: 0 !important;
  opacity: 0 !important;
  pointer-events: none !important;
  contain: none !important;
}

#left-nav-panel.openDrawer {
  width: var(--char-panel-expanded-width) !important;
  right: 0px !important;
  padding: 16px 12px !important;
  opacity: 1 !important;
  pointer-events: auto !important;
  border-left: 1px solid rgba(130, 233, 222, 0.2) !important;
}

/* 未展开时隐藏 */
#left-nav-panel:not(.openDrawer) {
  width: 0 !important;
  padding: 0 !important;
  border: none !important;
  overflow: hidden !important;
  opacity: 0 !important;
  pointer-events: none !important;
}

/* --- 左侧设置面板 --- */
#right-nav-panel {
  position: fixed !important;
  left: var(--nav-bar-width) !important;
  right: auto !important;
  top: 0 !important;
  bottom: 0 !important;
  width: 0 !important;
  height: 100vh !important;
  max-height: 100vh !important;
  background: linear-gradient(
    135deg,
    rgba(26, 31, 39, 0.95) 0%,
    rgba(30, 35, 43, 0.95) 100%
  ) !important;
  backdrop-filter: blur(12px) !important;
  -webkit-backdrop-filter: blur(12px) !important;
  border: none !important;
  border-right: 1px solid rgba(130, 233, 222, 0.2) !important;
  border-radius: 0 !important;
  box-shadow: 
    4px 0 24px rgba(0, 0, 0, 0.3),
    inset -1px 0 0 rgba(130, 233, 222, 0.08) !important;
  transition: 
    width var(--transition-speed) var(--transition-easing),
    padding var(--transition-speed) var(--transition-easing),
    opacity var(--transition-speed) ease !important;
  z-index: 999 !important;
  overflow-y: auto !important;
  overflow-x: hidden !important;
  padding: 0 !important;
  opacity: 0 !important;
  pointer-events: none !important;
  contain: none !important;
}

#right-nav-panel.openDrawer {
  width: var(--settings-panel-expanded-width) !important;
  left: var(--nav-bar-width) !important;
  padding: 16px !important;
  opacity: 1 !important;
  pointer-events: auto !important;
  border-right: 1px solid rgba(130, 233, 222, 0.2) !important;
}

/* 未展开时隐藏 */
#right-nav-panel:not(.openDrawer) {
  width: 0 !important;
  padding: 0 !important;
  border: none !important;
  overflow: hidden !important;
  opacity: 0 !important;
  pointer-events: none !important;
}

/* --- 主聊天区域 --- */
#sheld {
  position: fixed !important;
  left: calc(var(--nav-bar-width) + var(--settings-panel-width)) !important;
  right: var(--char-panel-width) !important;
  top: 0 !important;
  width: calc(
    100vw - var(--nav-bar-width) - var(--settings-panel-width) - var(--char-panel-width)
  ) !important;
  height: 100vh !important;
  max-height: 100vh !important;
  margin: 0 !important;
  padding: 0 !important;
  transition: all var(--transition-speed) var(--transition-easing) !important;
  overflow: hidden !important;
}

/* ========== 侧边栏布局系统结束 ========== */ 

/* --- 墨韵流光 --- */
:root {
  --font-main: 'LXGW WenKai Mono TC', 'Noto Serif SC', 'Kaiti SC', 'KaiTi', serif;
  --theme-color-jade: var(--SmartThemeQuoteColor);
  --theme-color-rouge: var(--SmartThemeUnderlineColor);
  --ui-bg: var(--SmartThemeBlurTintColor);
  --ui-bg-sec: var(--SmartThemeChatTintColor);
  --text-main: var(--SmartThemeBodyColor);
  --text-sec: var(--SmartThemeEmColor);
  /* 布局系统 */
  --nav-bar-width: 72px;
  --char-panel-width: 0px;
  --settings-panel-width: 0px;
  --char-panel-expanded-width: 420px;    /* 角色面板(右侧) */
  --settings-panel-expanded-width: 420px; /* 设置面板(左侧) */
  --transition-speed: 0.35s;
  --transition-easing: cubic-bezier(0.4, 0, 0.2, 1);

  /* 墨韵流光配色系统 */
  --gradient-main: linear-gradient(
    135deg,
    var(--theme-color-jade) 30%,
    color-mix(in srgb, var(--theme-color-jade) 50%, var(--theme-color-rouge) 50%) 50%,
    var(--theme-color-rouge) 70%
  );
  --gradient-primary: linear-gradient(135deg, rgba(130, 233, 222, 0.8), rgba(145, 220, 215, 0.8));
  --gradient-secondary: linear-gradient(135deg, rgba(249, 164, 200, 0.8), rgba(235, 180, 210, 0.8));
  --gradient-soft: linear-gradient(135deg, rgba(130, 233, 222, 0.08), rgba(249, 164, 200, 0.08));
  --gradient-hover: linear-gradient(135deg, rgba(130, 233, 222, 0.15), rgba(249, 164, 200, 0.15));
  --gradient-active: linear-gradient(135deg, rgba(130, 233, 222, 0.25), rgba(249, 164, 200, 0.25));
  --gradient-border: linear-gradient(90deg, rgba(130, 233, 222, 0.6), rgba(160, 210, 215, 0.6), rgba(249, 164, 200, 0.6));
  --gradient-glow: radial-gradient(circle, rgba(130, 233, 222, 0.15) 0%, rgba(249, 164, 200, 0.15) 50%, transparent 100%);

  /* 界面配置 */
  --panel-bg: rgba(22, 28, 35, 0.95);
  --panel-bg-sec: rgba(26, 31, 39, 0.88);
  --border-jade: rgba(130, 233, 222, 0.4);
  --border-rouge: rgba(249, 164, 200, 0.4);
  --ui-color-sec: color-mix(in srgb, var(--ui-bg) 88%, var(--text-main));

  /* 优化尺寸配置  */
  --topbar-height: 35px;
  --drawer-width: 435px; /* v3和v4的平衡点 */
  --box-radius: 16px;
  --tab-radius: 20px;
  --top-distance: 70px;
  --scroll-width: 8px;
  --animation-duration: 0.3s;
  --animation-easing: cubic-bezier(0.4, 0, 0.2, 1);
  --icon-size: 16px;
  --base-margin: 16px; 
  --content-padding: 16px; 
}

/* --- 动态面板宽度 --- */
/* 当左侧设置面板打开时 */
body:has(#right-nav-panel.openDrawer) {
  --settings-panel-width: var(--settings-panel-expanded-width);
}

/* 当右侧角色面板打开时 */
body:has(#left-nav-panel.openDrawer) {
  --char-panel-width: var(--char-panel-expanded-width);
}

.range-block-range {
    margin: 8px;
    flex: 4;
}

.range-block {
    height: min-content;
    display: block;
    flex-wrap: wrap;
    align-items: center;
    margin-bottom: 5px;
    justify-content: space-between;
}

/* --- 基础字体设置 --- */
* { 
  box-sizing: border-box; 
  word-wrap: break-word; 
  overflow-wrap: break-word;
}

.image-wrapper > * {
  display: none;
}

body, html, p, span, li {
  font-family: var(--font-main); 
  font-size: calc(var(--mainFontSize) * 1em);
  letter-spacing: 0.02em;
  word-spacing: 0.03em;
  line-height: 1.7;
  text-shadow: 0 1px 3px var(--SmartThemeShadowColor); 
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
}

#top-bar {
  position: absolute !important;
  top: 0px;
  height: var(--top-distance) !important;
  z-index: 100 !important;
  width: 100%;
}

/* Logo区域 */
#top-settings-holder::before {
  content: "墨";
  width: 52px;
  height: 52px;
  display: flex;
  align-items: center;
  justify-content: center;
  background: linear-gradient(
    135deg,
    rgba(130, 233, 222, 0.15) 0%,
    rgba(249, 164, 200, 0.1) 100%
  );
  border: 2px solid rgba(130, 233, 222, 0.4);
  border-radius: 50%;
  margin-bottom: 16px;
  font-size: 24px;
  font-weight: bold;
  color: rgba(130, 233, 222, 0.9);
  text-shadow: 0 0 12px rgba(130, 233, 222, 0.6);
  transition: all 0.4s cubic-bezier(0.34, 1.56, 0.64, 1);
  cursor: pointer;
  flex-shrink: 0;
  position: relative;
  overflow: hidden;
}

/* Logo光效层 */
#top-settings-holder::before::after {
  content: "";
  position: absolute;
  top: -50%;
  left: -50%;
  width: 200%;
  height: 200%;
  background: radial-gradient(
    circle,
    rgba(255, 255, 255, 0.3) 0%,
    transparent 70%
  );
  opacity: 0;
  transition: opacity 0.4s ease;
}

#top-settings-holder:hover::before {
  background: linear-gradient(
    135deg,
    rgba(130, 233, 222, 0.25) 0%,
    rgba(249, 164, 200, 0.15) 100%
  );
  border-color: rgba(130, 233, 222, 0.7);
  transform: scale(1.1) rotate(8deg);
  box-shadow: 
    0 0 25px rgba(130, 233, 222, 0.5),
    0 0 40px rgba(249, 164, 200, 0.3),
    inset 0 1px 0 rgba(255, 255, 255, 0.2);
  animation: logoBreath 2s ease-in-out infinite;
}

/* Logo呼吸动画 */
@keyframes logoBreath {
  0%, 100% {
    box-shadow: 
      0 0 20px rgba(130, 233, 222, 0.4),
      0 0 35px rgba(249, 164, 200, 0.2);
  }
  50% {
    box-shadow: 
      0 0 30px rgba(130, 233, 222, 0.6),
      0 0 50px rgba(249, 164, 200, 0.4);
  }
}

/* 分割线 */
#top-settings-holder::after {
  content: "";
  width: 40px;
  height: 2px;
  background: linear-gradient(
    90deg,
    transparent,
    rgba(130, 233, 222, 0.4),
    transparent
  );
  margin: 8px 0;
  flex-shrink: 0;
}

/* 抽屉改为按钮样式 */
.drawer {
  border: none !important;
  background: transparent !important;
  position: relative !important;
  overflow: visible !important;
  margin: 0 !important;
}

/* inline-drawer 内联抽屉样式 - 类似 h4 标签 */
.inline-drawer:not(#logprobsViewer) {
  /* 保持原有布局 */
  display: inline-block !important;
  position: relative !important;
  width: 97% !important;

  /* 添加左侧边框（类似 h4） */
  border-width: 0 0 0 4px !important;
  border-color: transparent !important;
  border-style: solid !important;
  border-radius: 0 !important;
  border-image: linear-gradient(
    to bottom,
    transparent 10%,
    rgba(130, 233, 222, 0.9) 10%,
    rgba(130, 233, 222, 0.9) 90%,
    transparent 90%
  ) 1 100% !important;

  /* 背景渐变和模糊效果（类似 h4） */
  background: linear-gradient(
    90deg,
    rgba(130, 233, 222, 0.15) 0%,
    rgba(130, 233, 222, 0.08) 50%,
    transparent 80%
  ) !important;
  backdrop-filter: blur(3px) !important;
  -webkit-backdrop-filter: blur(3px) !important;

