/* logprobsViewer 特殊处理 - 确保有 hidden 类时隐藏 */
#logprobsViewer.hidden {
  display: none !important;
  opacity: 0 !important;
  visibility: hidden !important;
  pointer-events: none !important;
}

/* === 独立浮动窗口样式 === */
/* 为 floatingPrompt, cfgConfig, logprobsViewer 创建独立的浮动窗口 */
/* ID 选择器优先级高于 .drawer-content 类选择器 */
#floatingPrompt,
#cfgConfig,
#logprobsViewer {
  position: fixed !important;

  /* 覆盖 drawer-content 的强制定位 - 使用非 !important 让内联样式能覆盖 */
  top: 100px;
  bottom: unset !important; /* 确保不固定底部 */
  left: calc(50vw - 300px);
  right: unset !important; /* 确保不固定右侧 */

  /* 窗口尺寸 - 横向窗口,宽度大于高度 */
  width: 750px; /* 增大宽度 */
  max-width: none; /* 允许调整到任意宽度 */
  height: 500px; /* 默认自适应,但可以被内联样式覆盖 */
  min-width: 400px;
  min-height: 200px; /* 设置合理的最小高度 */

  /* 样式 */
  background: linear-gradient(
    135deg,
    rgba(22, 28, 35, 0.98) 0%,
    rgba(26, 31, 39, 0.95) 100%
  ) !important;
  backdrop-filter: blur(16px) saturate(1.1) !important;
  -webkit-backdrop-filter: blur(16px) saturate(1.1) !important;
  border: 2px solid rgba(130, 233, 222, 0.3) !important;
  border-radius: 12px !important;
  box-shadow:
    0 20px 60px rgba(0, 0, 0, 0.5),
    0 10px 30px rgba(130, 233, 222, 0.15),
    inset 0 1px 0 rgba(255, 255, 255, 0.15) !important;

  /* 布局 */
  padding: 16px !important;
  overflow: auto !important; /* 改为 auto,如果内容超出则滚动 */
  z-index: 1500 !important;
  margin: 0 !important;

  /* 不使用 transform,避免干扰拖拽计算 */
  transform: none !important;

  /* 动画 - 只对视觉效果做过渡,不影响位置变化 */
  transition: box-shadow 0.3s cubic-bezier(0.4, 0, 0.2, 1),
              border-color 0.3s cubic-bezier(0.4, 0, 0.2, 1) !important;
}

/* 窗口隐藏状态 */
#movingDivs.hidden,
#floatingPrompt.hidden,
#cfgConfig.hidden {
  display: none !important;
  opacity: 0 !important;
  visibility: hidden !important;
  pointer-events: none !important;
}

/* 窗口悬停效果 */
#movingDivs:hover,
#floatingPrompt:hover,
#cfgConfig:hover,
#logprobsViewer:hover {
  border-color: rgba(130, 233, 222, 0.5) !important;
  box-shadow:
    0 25px 70px rgba(0, 0, 0, 0.6),
    0 15px 40px rgba(130, 233, 222, 0.25),
    0 0 40px rgba(249, 164, 200, 0.15),
    inset 0 1px 0 rgba(255, 255, 255, 0.2) !important;
}

/* 窗口内容区域 - 增加内边距使布局更宽松 */
#floatingPrompt .logprobs_panel_content,
#cfgConfig .logprobs_panel_content,
#logprobsViewer .logprobs_panel_content {
  max-height: none; /* 不限制最大高度 */
  height: 100%; /* 填满父容器 */
  overflow-y: auto; /* 内容过多时滚动 */
  overflow-x: hidden !important;
  padding: 12px !important;
  box-sizing: border-box !important;
}

/* 窗口头部自适应高度 */
#floatingPrompt .logprobs_panel_header,
#cfgConfig .logprobs_panel_header,
#logprobsViewer .logprobs_panel_header {
  height: auto;
  min-height: auto;
