}

/* 窗口内元素间距 */
#floatingPrompt .logprobs_panel_content > *,
#cfgConfig .logprobs_panel_content > *,
#logprobsViewer .logprobs_panel_content > * {
  margin-bottom: 12px !important;
}

#floatingPrompt .logprobs_panel_content > *:last-child,
#cfgConfig .logprobs_panel_content > *:last-child,
#logprobsViewer .logprobs_panel_content > *:last-child {
  margin-bottom: 0 !important;
}

/* inline-drawer-toggle 和 inline-drawer-header 样式 */
