/* 按钮内部装饰层 */
.drawer-toggle.drawer-header::before {
  content: '' !important;
  position: absolute !important;
  top: 2px; left: 2px; right: 2px; bottom: 2px !important;
  background: linear-gradient(
    135deg,
    rgba(130, 233, 222, 0.1) 0%,
    transparent 50%,
    rgba(249, 164, 200, 0.05) 100%
  ) !important;
  opacity: 0 !important;
