    0 0 10px rgba(130, 233, 222, 0.8),
    0 0 20px rgba(130, 233, 222, 0.4),
    0 1px 2px rgba(0, 0, 0, 0.3) !important;
  transform: scale(1.1) !important;
  filter: 
    drop-shadow(0 2px 4px rgba(0, 0, 0, 0.4))
    drop-shadow(0 0 8px rgba(130, 233, 222, 0.5)) !important;
}

.drawer-toggle:active .drawer-icon {
  transform: scale(1.05) !important;
  color: rgba(255, 255, 255, 0.9) !important;
}

.drawer-toggle.selected .drawer-icon,
.drawer-toggle[aria-expanded="true"] .drawer-icon {
  color: rgba(255, 255, 255, 0.95) !important;
  text-shadow: 
    0 0 12px rgba(255, 255, 255, 0.6),
    0 0 20px rgba(255, 255, 255, 0.3),
    0 2px 4px rgba(0, 0, 0, 0.4) !important;
  transform: scale(1.1) !important;
  filter: 
    drop-shadow(0 2px 4px rgba(0, 0, 0, 0.5))
    drop-shadow(0 0 10px rgba(255, 255, 255, 0.3)) !important;
}

/* 按钮脉冲动画 */
@keyframes buttonPulse {
  0%, 100% { box-shadow: 0 0 0 0 rgba(130, 233, 222, 0.4); }
  50% { box-shadow: 0 0 0 8px rgba(130, 233, 222, 0); }
}

.drawer-toggle.drawer-header.selected,
.drawer-toggle.drawer-header[aria-expanded="true"] {
  animation: buttonPulse 2s ease-in-out infinite !important;
}

/* 抽屉内容调整 */
.drawer-content:not(#floatingPrompt):not(#cfgConfig):not(#logprobsViewer) {
  position: fixed !important;
  top: 0 !important;
  bottom: 0 !important;
  height: 100vh !important;
  background: linear-gradient(135deg, var(--panel-bg), var(--panel-bg-sec)) !important;
  backdrop-filter: blur(14px) saturate(1.08) !important;
  -webkit-backdrop-filter: blur(14px) saturate(1.08) !important;
  border: 1px solid var(--border-jade) !important;
  border-radius: var(--box-radius) !important;
  box-shadow:
    0 18px 36px rgba(0, 0, 0, 0.4),
    0 10px 22px rgba(130, 233, 222, 0.12),
    inset 0 1px 0 rgba(255, 255, 255, 0.12) !important;
  z-index: 999 !important;
  overflow-y: auto !important;
  overflow-x: hidden !important;
  transition: all var(--animation-duration) var(--animation-easing) !important;
  padding: 28px 32px !important;
  margin: 0 !important;
  contain: none !important;
  clip-path: none !important;
  opacity: 1 !important;
  visibility: visible !important;
}

body .drawer-content:not(#right-nav-panel):not(#left-nav-panel):not(#floatingPrompt):not(#cfgConfig):not(#logprobsViewer) {
  /* 完全独立的定位,不受任何父级影响 */
  position: fixed !important;
  left: calc(var(--nav-bar-width) + var(--settings-panel-width)) !important;
  right: var(--char-panel-width) !important;
  top: 0 !important;
  bottom: 0 !important;
  width: calc(100vw - var(--nav-bar-width) - var(--settings-panel-width) - var(--char-panel-width)) !important;
  height: 100vh !important;
  max-width: none !important;
  max-height: none !important;
  min-width: 400px !important;
  /* 重置所有可能的限制 */
  transform: none !important;
  perspective: none !important;
  contain: none !important;
  overflow-y: auto !important;
  overflow-x: hidden !important;
  clip: auto !important;
  clip-path: none !important;
  /* 样式 */
  border-radius: 0 !important;
  border-left: 1px solid rgba(130, 233, 222, 0.25) !important;
  border-right: 1px solid rgba(130, 233, 222, 0.15) !important;
  box-shadow:
    inset 0 1px 0 rgba(255, 255, 255, 0.12),
    inset 0 -1px 0 rgba(0, 0, 0, 0.35) !important;
  padding: 32px 42px !important;
}

#right-nav-panel,
#left-nav-panel {
  position: fixed !important;
  top: 0 !important;
  bottom: 0 !important;
  height: 100vh !important;
  max-height: 100vh !important;
  border-radius: 0 !important;
  contain: none !important;
  overflow-y: auto !important;
  overflow-x: hidden !important;
}

/* fillLeft 和 fillRight 桌面端定位 */
body .drawer-content.fillLeft:not(#right-nav-panel):not(#left-nav-panel):not(#floatingPrompt):not(#cfgConfig):not(#logprobsViewer),
body .fillLeft.drawer-content:not(#right-nav-panel):not(#left-nav-panel):not(#floatingPrompt):not(#cfgConfig):not(#logprobsViewer) {
  /* 从导航栏右侧到屏幕中间 */
