  min-width: 400px !important;
}

body .drawer-content.fillRight:not(#right-nav-panel):not(#left-nav-panel):not(#floatingPrompt):not(#cfgConfig):not(#logprobsViewer),
body .fillRight.drawer-content:not(#right-nav-panel):not(#left-nav-panel):not(#floatingPrompt):not(#cfgConfig):not(#logprobsViewer) {
  /* 从屏幕中间到屏幕右侧 */
  left: 50% !important;
  right: 0 !important;
  width: 50vw !important;
  min-width: 400px !important;
}


