.fa-circle-stop::before {
  content: "🔔";
  font-size: 20px;
  vertical-align: middle;
  display: inline-flex;
  justify-content: center;
  align-items: center;
  animation: gentleSway 4s ease-in-out infinite;
  max-width: 1em;
  transform-origin: center;
  line-height: 1;
  transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
  filter: drop-shadow(0 2px 4px rgba(0, 0, 0, 0.3));
}

/* 飘动动画 */
@keyframes gentleSway {
  0%, 100% { 
    transform: rotate(-20deg) scale(1); /* 从-8deg增加到-20deg */
  }
  25% { 
    transform: rotate(-5deg) scale(1.08); /* 从0deg改为-5deg，增加过渡层次 */
  }
  50% { 
    transform: rotate(20deg) scale(1); /* 从8deg增加到20deg */
  }
  75% { 
    transform: rotate(5deg) scale(0.92); /* 从0deg改为5deg，增加过渡层次 */
  }
}

/* 增强的悬停特效 */
.fa-circle-stop:hover::before {
  filter: 
    drop-shadow(0 0 8px rgba(249, 164, 200, 0.8)) 
    drop-shadow(0 0 15px rgba(130, 233, 222, 0.6))
    brightness(1.3);
  transform: scale(1.5) rotate(25deg); /* 从1.4增加到1.5，从15deg增加到25deg */
  animation: none;
}
/* 发送按钮美化 */
#send_but {
  background: linear-gradient(
    135deg,
    rgba(130, 233, 222, 0.8) 0%,
    rgba(249, 164, 200, 0.6) 100%
  );
  border: 1px solid rgba(130, 233, 222, 0.6);
  border-radius: 8px;
  color: white;
  font-weight: 600;
  text-shadow: 0 1px 2px rgba(0, 0, 0, 0.4);
  box-shadow: 
    0 4px 15px rgba(130, 233, 222, 0.3),
    inset 0 1px 0 rgba(255, 255, 255, 0.2);
  transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
  backdrop-filter: blur(5px);
  -webkit-backdrop-filter: blur(5px);
}

#send_but:hover {
  background: linear-gradient(
    135deg,
    rgba(130, 233, 222, 1) 0%,
    rgba(249, 164, 200, 0.8) 100%
  );
  border-color: rgba(130, 233, 222, 0.8);
  box-shadow: 
    0 6px 20px rgba(130, 233, 222, 0.4),
    0 0 25px rgba(249, 164, 200, 0.3),
    inset 0 1px 0 rgba(255, 255, 255, 0.3);
  transform: translateY(-2px) scale(1.05);
}

#send_but:active {
  transform: translateY(0) scale(1);
  box-shadow: 
    0 2px 8px rgba(130, 233, 222, 0.3),
    inset 0 1px 0 rgba(255, 255, 255, 0.2);
}

/* 聊天区域修复 */
#chat {
    background: radial-gradient(circle at center, rgba(22, 28, 35, 0.75) 0%, rgba(20, 24, 30, 0.65) 70%);
    backdrop-filter: blur(8px) saturate(1.2) brightness(1.05);
    -webkit-backdrop-filter: blur(8px) saturate(1.2) brightness(1.05);
    padding: calc(var(--scroll-width) + 4px) 0 var(--scroll-width) var(--scroll-width);
    margin: 0 0;
    border: 1px solid var(--border-jade);
    box-shadow: inset 0 1px 0 rgba(255, 255, 255, 0.08), 0 8px 25px rgba(0, 0, 0, 0.4), 0 0 20px rgba(130, 233, 222, 0.1);
    overflow-y: scroll;
    align-items: center;
    max-height: calc(100dvh - var(--topBarBlockSize) - 20px);
}

/* --- 主体内容适配 --- */
body {
  padding-top: calc(var(--topbar-height) + var(--base-margin));
  transition: padding-top var(--animation-duration) var(--animation-easing);
}


/* 完全移除消息文本边框和装饰 */
p {
  transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
  transform-origin: center;
  position: relative;
  border-radius: 8px;
  overflow: hidden;
  border: none;
}

/* 渐变背景层 */
p::before {
  content: "";
  position: absolute;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  background: linear-gradient(
    135deg,
    rgba(130, 233, 222, 0.15) 0%,
    rgba(249, 164, 200, 0.1) 50%,
    rgba(130, 233, 222, 0.08) 100%
  );
  opacity: 0;
  transition: opacity 0.3s ease;
  z-index: -1;
  border-radius: 8px;
}

/* 悬停效果 */
p:hover {
  transform: scale(1.01) translateY(-2px);
  z-index: 10;
  border: 1px solid rgba(130, 233, 222, 0.7);
  box-shadow: 
    0 8px 25px rgba(0, 0, 0, 0.15),
    0 0 20px rgba(130, 233, 222, 0.2);
}

/* 悬停时渐变背景显示 */
p:hover::before {
  opacity: 1;
}

/* 针对消息文本p标签特别优化 */
.mes_text p {
  transition: all 0.4s cubic-bezier(0.4, 0, 0.2, 1);
  transform-origin: center;
  position: relative;
  border-radius: 10px;
  overflow: hidden;
  margin: 8px 0;
  padding: 12px 16px;
  border: none;
}

.mes_text p::before {
  content: "";
  position: absolute;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  background: linear-gradient(
    135deg,
    rgba(130, 233, 222, 0.18) 0%,
    rgba(249, 164, 200, 0.12) 50%,
    rgba(130, 233, 222, 0.1) 100%
  );
  opacity: 0;
  transition: all 0.4s ease;
  z-index: -1;
  border-radius: 10px;
}

.mes_text p:hover {
  transform: scale(1.01) translateY(-3px);
  z-index: 15;
  border: 1px solid rgba(130, 233, 222, 0.8);
  box-shadow: 
    0 12px 35px rgba(0, 0, 0, 0.2),
    0 0 25px rgba(130, 233, 222, 0.25),
    0 0 40px rgba(249, 164, 200, 0.15);
}

.mes_text p:hover::before {
  opacity: 1;
  box-shadow: inset 0 1px 0 rgba(255, 255, 255, 0.08);
}

/* 用户消息特别效果 */
.mes[is_user="true"] .mes_text p::before {
  background: linear-gradient(
    135deg,
    rgba(249, 164, 200, 0.18) 0%,
    rgba(130, 233, 222, 0.12) 50%,
    rgba(249, 164, 200, 0.1) 100%
  );
}

.mes[is_user="true"] .mes_text p:hover {
  border-color: rgba(249, 164, 200, 0.8);
}

/* AI消息特别效果 */
.mes[is_user="false"] .mes_text p::before {
  background: linear-gradient(
    135deg,
    rgba(130, 233, 222, 0.18) 0%,
    rgba(160, 210, 215, 0.12) 50%,
    rgba(130, 233, 222, 0.1) 100%
  );
}

.mes[is_user="false"] .mes_text p:hover {
  border-color: rgba(130, 233, 222, 0.8);
}

/* 流光动画效果 */
@keyframes shimmerFlow {
  0% { background-position: -200% 0; }
  100% { background-position: 200% 0; }
}

.mes_text p:hover::after {
  content: "";
  position: absolute;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  background: linear-gradient(
    90deg,
    transparent 20%,
    rgba(130, 233, 222, 0.15) 50%,
    transparent 80%
  );
  background-size: 200% 100%;
  animation: shimmerFlow 2s ease-in-out infinite;
  z-index: 1;
  pointer-events: none;
  border-radius: 10px;
}

/* --- 按钮和图标显示修复 --- */


/* 修复按钮容器布局 */
.flex-container.alignitemscenter {
  display: flex;
  align-items: center;
  gap: 2px;
  flex-wrap: wrap;
  margin: 4px 0;
  padding: 4px;
  background: var(--gradient-soft);
  border-radius: var(--box-radius);
  border: 1px solid var(--border-jade);
}

/* 按钮样式修复 */
.menu_button {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 6px;
  padding: 10px 14px;
  margin: 2px;
  background: var(--gradient-soft);
  border: 1px solid var(--border-jade);
  border-radius: 10px;
  color: var(--text-main);
  font-size: 14px;
  line-height: 1.2;
  cursor: pointer;
  transition: all var(--animation-duration) var(--animation-easing);
  white-space: nowrap;
  min-height: 36px;
  text-decoration: none;
  position: relative;
  overflow: hidden;
}


.menu_button:hover::before {
  opacity: 1;
}

.menu_button:hover {
  border-color: var(--theme-color-jade);
  box-shadow: 
    0 0 15px rgba(130, 233, 222, 0.4),
    0 4px 8px rgba(0, 0, 0, 0.15);
  transform: translateY(-1px);
  color: var(--text-main);
}

.menu_button:active {
  transform: translateY(0) scale(0.96);
  background: var(--gradient-active);
  box-shadow: 
    inset 0 2px 4px rgba(0, 0, 0, 0.15),
    0 0 10px rgba(130, 233, 222, 0.3);
}

.menu_button i {
  font-size: var(--icon-size);
  color: inherit;
  margin-right: 4px;
}

.menu_button span {
  font-size: 13px;
  color: inherit;
}

/* 修复图标按钮 */
.menu_button.menu_button_icon {
  min-width: 30px;
  min-height: 30px;
  padding: 0px;
}

.menu_button.menu_button_icon i {
  margin-right: 0;
}

.menu_button.menu_button_icon span {
  margin-left: 4px;
}

/* 危险按钮样式 */
.redWarningBG {
  background: linear-gradient(135deg, rgba(220, 38, 38, 0.2), rgba(185, 28, 28, 0.2));
  border-color: rgba(220, 38, 38, 0.6);
}

.redWarningBG:hover {
  background: linear-gradient(135deg, rgba(220, 38, 38, 0.3), rgba(185, 28, 28, 0.3));
  border-color: rgba(220, 38, 38, 0.8);
  box-shadow: 
    0 0 15px rgba(220, 38, 38, 0.4),
    0 4px 8px rgba(0, 0, 0, 0.15);
}

/* --- Select2下拉框修复 --- */
.select2-container {
  width: auto;
  min-width: 150px;
  margin: 0 4px;
}

.select2-selection {
  background: var(--panel-bg);
  border: 1px solid var(--border-jade);
  border-radius: 8px;
  color: var(--text-main);
  font-family: var(--font-main);
  font-size: 13px;
  height: 36px;
  line-height: 34px;
}

.select2-selection__rendered {
  color: var(--text-main);
  padding-left: 10px;
  padding-right: 24px;
}

.select2-selection__arrow {
  height: 34px;
  right: 6px;
}

.select2-selection__clear {
  color: var(--text-sec);
  font-size: 16px;
  line-height: 34px;
  margin-right: 24px;
}

/* --- 动画效果 --- */
@keyframes slideInLeft {
  from { transform: translateX(-100%); opacity: 0; }
  to { transform: translateX(0); opacity: 1; }
}

@keyframes slideInRight {
  from { transform: translateX(100%); opacity: 0; }
  to { transform: translateX(0); opacity: 1; }
}

@keyframes fadeIn {
  from { opacity: 0; transform: translateY(10px); }
  to { opacity: 1; transform: translateY(0); }
}

@keyframes glow {
  0%, 100% { box-shadow: 0 0 15px rgba(130, 233, 222, 0.3); }
  50% { box-shadow: 0 0 25px rgba(130, 233, 222, 0.6), 0 0 35px rgba(249, 164, 200, 0.3); }
}

@keyframes pulse {
  0%, 100% { transform: scale(1); }
  50% { transform: scale(1.02); }
}

